import React, { useState, useEffect, useCallback } from 'react';
import { attendanceAPI, employeeAPI } from '../utils/api';
import useWebSocket from '../hooks/useWebSocket';
import './Dashboard.css';

function StatCard({ icon, label, value, sub, color }) {
  return (
    <div className="stat-card" style={{ borderTop: `3px solid ${color}` }}>
      <div className="stat-icon">{icon}</div>
      <div className="stat-body">
        <div className="stat-value" style={{ color }}>{value}</div>
        <div className="stat-label">{label}</div>
        {sub && <div className="stat-sub">{sub}</div>}
      </div>
    </div>
  );
}

export default function Dashboard() {
  const [summary, setSummary] = useState(null);
  const [empStats, setEmpStats] = useState(null);
  const [log, setLog] = useState([]);

  const fetchData = async () => {
    const [s, e] = await Promise.all([attendanceAPI.todaySummary(), employeeAPI.stats()]);
    setSummary(s.data);
    setEmpStats(e.data);
    const feed = await attendanceAPI.liveFeed();
    setLog(feed.data);
  };

  useEffect(() => { fetchData(); const t = setInterval(fetchData, 30000); return () => clearInterval(t); }, []);

  const handleWsMessage = useCallback((data) => {
    if (data.type === 'attendance_update') {
      setLog(prev => [{
        id: Date.now(),
        employee_name: data.name,
        employee_name_kh: data.name_kh,
        department: data.department,
        employee_id: data.employee_id,
        timestamp: data.timestamp,
        camera_name: data.camera_id,
        confidence: null,
        is_unknown: false,
      }, ...prev.slice(0, 99)]);
    }
  }, []);

  useWebSocket(`ws://${window.location.hostname}:8000/ws/dashboard/`, handleWsMessage);

  const today = new Date().toLocaleDateString('km-KH', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

  return (
    <div>
      <div className="page-header">
        <h1>📊 Dashboard</h1>
        <p>{today}</p>
      </div>

      <div className="grid-4" style={{ marginBottom: 24 }}>
        <StatCard icon="👥" label="Total Employees" value={summary?.total_employees ?? '—'} color="#3b82f6" />
        <StatCard icon="✅" label="Present Today" value={summary?.present ?? '—'} sub={`${summary?.attendance_rate ?? 0}% attendance`} color="#10b981" />
        <StatCard icon="❌" label="Absent" value={summary?.absent ?? '—'} color="#ef4444" />
        <StatCard icon="⚠️" label="Unknown Detected" value={summary?.unknown_detections ?? '—'} color="#f59e0b" />
      </div>

      <div className="grid-2" style={{ marginBottom: 24 }}>
        <div className="card">
          <div className="card-title">📹 Face Registration Status</div>
          {empStats && (
            <div>
              <div className="progress-row">
                <span>Registered</span>
                <span className="badge badge-green">{empStats.face_registered}</span>
              </div>
              <div className="progress-bar-bg">
                <div className="progress-bar-fill" style={{ width: `${empStats.total ? (empStats.face_registered / empStats.total) * 100 : 0}%` }} />
              </div>
              <div className="progress-row" style={{ marginTop: 8 }}>
                <span>Not Registered</span>
                <span className="badge badge-red">{empStats.not_registered}</span>
              </div>
            </div>
          )}
        </div>

        <div className="card">
          <div className="card-title">⏱️ Quick Stats</div>
          <div className="quick-stats">
            <div className="qs-item"><span>Attendance Rate</span><span style={{ color: '#10b981', fontWeight: 700 }}>{summary?.attendance_rate ?? 0}%</span></div>
            <div className="qs-item"><span>Total Registered Faces</span><span style={{ color: '#3b82f6', fontWeight: 700 }}>{empStats?.face_registered ?? 0}</span></div>
            <div className="qs-item"><span>Today Unknown Alerts</span><span style={{ color: '#f59e0b', fontWeight: 700 }}>{summary?.unknown_detections ?? 0}</span></div>
          </div>
        </div>
      </div>

      <div className="card">
        <div className="card-title">🔴 Live Attendance Feed</div>
        <div className="live-table-wrap">
          <table className="live-table">
            <thead>
              <tr>
                <th>Time</th>
                <th>Employee ID</th>
                <th>Name</th>
                <th>Khmer Name</th>
                <th>Department</th>
                <th>Camera</th>
                <th>Status</th>
              </tr>
            </thead>
            <tbody>
              {log.map((r, i) => (
                <tr key={r.id || i} className={r.is_unknown ? 'row-unknown' : ''}>
                  <td>{new Date(r.timestamp).toLocaleTimeString()}</td>
                  <td>{r.employee_id || '—'}</td>
                  <td>{r.is_unknown ? <span style={{ color: '#ef4444' }}>Unknown</span> : r.employee_name}</td>
                  <td>{r.employee_name_kh || '—'}</td>
                  <td>{r.department || '—'}</td>
                  <td>{r.camera_name || '—'}</td>
                  <td><span className={`badge ${r.is_unknown ? 'badge-red' : 'badge-green'}`}>{r.is_unknown ? 'Unknown' : 'Check In'}</span></td>
                </tr>
              ))}
              {log.length === 0 && (
                <tr><td colSpan={7} style={{ textAlign: 'center', color: '#475569', padding: 32 }}>No records yet today</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}
